import React, { useCallback, useRef } from 'react'
import { useCountdownStore } from './useCountDownStore'
import { playTick } from './util'


function useCountdown() {
    const { initialSeconds, setIsRunning, setTimeLeft, timeLeft } = useCountdownStore((state) => state)
    const intervalRef = useRef(null)

    const start = (timeLeft) => {
        setIsRunning(true)
        if (timeLeft <= 0 && intervalRef.current != null) {
            pause()
            // setTimeLeft(0)
        } else {
            playTick()
            const newTimeLeft = timeLeft - 1
            setTimeLeft(newTimeLeft)
            intervalRef.current = setTimeout((value) => {
                start(value)
            }, 1000, newTimeLeft)
        }
    }

    const pause = useCallback(() => {
        clearInterval(intervalRef.current)
        setIsRunning(false)
    }, [])

    const reset = useCallback(() => {
        pause()
        setTimeLeft(initialSeconds)
    }, [initialSeconds])

    return { start, pause, reset }
}

export default useCountdown
